app.get('/login', (req, res) => {
    const token = req.query.token;
    res.cookie('session', token);  // no security flags
    res.send('logged in');
});

findings.fix:
Always set security cookie flags:

res.cookie('session', token, {
    httpOnly: true,
    secure: true,
    sameSite: 'Strict',
    maxAge: 3600000
});

